parameters.jsCode:
const stdout = $input.first().json.stdout || '{}';
let report;
try {
  report = JSON.parse(stdout);
} catch(e) {
  return [{ json: { error: 'parse failed', raw: stdout.slice(0,500), has_changes: false } }];
}
const ch = report.changes || {};
const newModels = ch.new_models || [];
const topNew = newModels.slice(0,15)
  .map(m => `• [${m.category}] ${m.name} (${(m.providers||[]).join(', ')})`)
  .join('\n');
return [{ json: {
  has_changes: (ch.total_new || 0) > 0 || (ch.price_changes || []).length > 0,
  total_new: ch.total_new || 0,
  total_models: ch.total_new_total || 0,
  price_changes_count: (ch.price_changes || []).length,
  new_providers_count: (ch.new_providers || []).length,
  top_new_text: topNew || '(brak nowych modeli)',
  date: ch.date || new Date().toISOString().split('T')[0],
  report_text: (report.report || '').slice(0, 3000),
}}];

